Test 1: Chunking Completeness
Every document in the corpus should be fully chunked: the first chunk starts at page 1 and the last chunk ends at or beyond the document’s page count.


Show code
# Get total pages per document from us_body (aggregated by package_id)
id_col &lt;- if ("package_id" %in% names(us_body)) "package_id" else "doc_id"

doc_pages &lt;- us_body |&gt;
  group_by(across(all_of(id_col))) |&gt;
  summarize(
    n_pages_doc = sum(map_int(text, length)),
    .groups = "drop"
  ) |&gt;
  rename(doc_id = all_of(id_col))

# Get chunk coverage per document
chunk_coverage &lt;- chunks |&gt;
  group_by(doc_id) |&gt;
  summarize(
    min_start = min(start_page),
    max_end = max(end_page),
    n_chunks = n(),
    .groups = "drop"
  )

# Join and check
coverage_check &lt;- doc_pages |&gt;
  filter(n_pages_doc &gt; 0) |&gt;
  inner_join(chunk_coverage, by = "doc_id") |&gt;
  mutate(
    starts_at_1 = min_start == 1,
    covers_end = max_end &gt;= n_pages_doc,
    ok = starts_at_1 & covers_end
  )

n_fail_start &lt;- sum(!coverage_check$starts_at_1)
n_fail_end &lt;- sum(!coverage_check$covers_end)
n_docs_checked &lt;- nrow(coverage_check)
all_ok &lt;- all(coverage_check$ok)




